ALGORITHM PhongShading(polygon, vertices, light, material):
BEGIN
 // Step 1: Compute vertex normals (same as Gouraud)
 FOR EACH vertex IN vertices:
 vertex.normal = AverageNormalsOfAdjacentFaces(vertex)
 END FOR

 // Step 2: Rasterize and interpolate normals
 FOR EACH fragment (pixel) IN polygon:
 // Get barycentric coordinates
 bary = GetBarycentricCoordinates(fragment.position, polygon)

 // Interpolate normal at this pixel
 normal = bary.alpha * v1.normal + bary.beta * v2.normal + bary.gamma * v3.normal
 normal = Normalize(normal)

 // Compute view direction
 viewDir = Normalize(camera.position - fragment.position)

 // Calculate Phong illumination at this pixel
 fragment.color = PhongIllumination(fragment.position, normal, material, light, viewDir)

 SetPixelColor(fragment.x, fragment.y, fragment.color)
 END FOR
END
